pub async fn get_users_by_active(pool: &sqlx::PgPool, active: bool) -> Result<Vec<GetUsersByActiveRow>, sqlx::Error> {
    sqlx::query_as!(GetUsersByActiveRow, "SELECT id, name FROM users WHERE active = $1", active)
        .fetch_all(pool)
        .await
}

